mapper.select:
select t1.*, t3.ThirdPartyName as third_party_name, t4.NAME as transformation_name from VzDataQuality.dbo.tb_collectiontimingdata as t1 left join VzDataQuality.dbo.tb_collectiontask as t2 on t1.task_id=t2.id left join VzDataQuality.dbo.ThridParty as t3 on t1.company_id=t3.SysId left join VzDataQuality.dbo.r_transformation as t4 on t1.tran_id=t4.ID_TRANSFORMATION where t1.status!=2
and t1.task_id=#{map.task_id}
and t1.work_untis_name like concat('%',#{map.work_untis_name},'%')
and t1.type=#{map.type}
